INSERT INTO `admin_operation_log` (`id`, `user_id`, `path`, `method`, `ip`, `input`, `created_at`, `updated_at`) VALUES (1335, 1, 'admin/articles/14', 'PUT', '175.169.82.214', '{\"title\":\"agreement\",\"content\":\"<p>\\u6b22\\u8fce\\u53c2\\u4e0e\\u5708\\u5708\\u65e7\\u8863\\u56de\\u6536\\uff0c\\u5f00\\u542f\\u73af\\u4fdd\\u65b0\\u884c\\u52a8\\uff0c\\u6211\\u4eec\\u5c06\\u4ee5\\u672c\\u58f0\\u660e\\u5bf9\\u8bbf\\u95ee\\u8005\\u9690\\u79c1\\u4fdd\\u62a4\\u7684\\u627f\\u8bfa\\u3002\\u672c\\u7ad9\\u7684\\u9690\\u79c1\\u7533\\u660e\\u6301\\u7eed\\u4e0d\\u65ad\\u6539\\u8fdb\\u4e2d\\uff0c\\u6211\\u4eec\\u4f1a\\u968f\\u65f6\\u66f4\\u65b0\\u6211\\u4eec\\u7684\\u9690\\u79c1\\u7533\\u660e\\u3002\\u6211\\u4eec\\u6b22\\u8fce\\u60a8\\u968f\\u65f6\\u6765\\u67e5\\u770b\\u672c\\u534f\\u8bae\\u3002\\u4f60\\u5df2\\u7ecf\\u540c\\u610f\\u6211\\u4eec\\u6309\\u7167\\u672c\\u534f\\u8bae\\u7533\\u660e\\u3002\\u672c\\u9690\\u79c1\\u7533\\u660e\\u7684\\u5168\\u90e8\\u6761\\u6b3e\\u5c5e\\u4e8e\\u8be5\\u534f\\u8bae\\u7684\\u4e00\\u90e8\\u4efd\\u3002<\\/p><p>\\u4e00\\u3001 \\u56de\\u6536\\u5904\\u7f6e<\\/p><p>&nbsp;1.\\u5708\\u5708\\u65e7\\u8863\\u56de\\u6536\\u76ee\\u524d\\u652f\\u6301\\u5404\\u7c7b\\u65e7\\u8863\\u7269\\u7684\\u56de\\u6536\\uff0c\\u5305\\u62ec\\u4f46\\u4e0d\\u9650\\u4e8e\\u8863\\u7269\\uff0c\\u978b\\u5b50\\uff0c\\u5305\\u5305\\uff0c\\u6bdb\\u7ed2\\u73a9\\u5177\\uff0c\\u5e8a\\u5355\\u88ab\\u5957\\u7b49\\u7eba\\u7ec7\\u54c1\\uff0c\\u76ee\\u524d\\u5bf9\\u8863\\u7269\\u7684\\u6b3e\\u5f0f\\u548c\\u65b0\\u65e7\\u7a0b\\u5ea6\\u6ca1\\u6709\\u4e25\\u683c\\u7684\\u8981\\u6c42\\uff0c\\u53ea\\u8981\\u4e0d\\u4e25\\u91cd\\u5f71\\u54cd\\u4e8c\\u6b21\\u7a7f\\u7740\\u5219\\u89c6\\u4e3a\\u7b26\\u5408\\u56de\\u6536\\u6807\\u51c6;<\\/p><p>&nbsp;2.\\u60a8\\u7684\\u56de\\u6536\\u884c\\u4e3a\\u88ab\\u89c6\\u4e3a\\u73af\\u4fdd\\u516c\\u76ca\\u884c\\u4e3a\\uff0c\\u5708\\u5708\\u4e0d\\u4f1a\\u4ee5\\u76f4\\u63a5\\u73b0\\u91d1\\u7684\\u5f62\\u5f0f\\u652f\\u4ed8\\u7ed9\\u60a8\\u56de\\u6536\\u8d39\\u7528\\uff0c\\u4e3a\\u63d0\\u5021\\u548c\\u9f13\\u52b1\\u60a8\\u7684\\u73af\\u4fdd\\u516c\\u76ca\\u884c\\u4e3a\\uff0c\\u6211\\u4eec\\u53ef\\u80fd\\u4f1a\\u4ee5\\u79ef\\u5206\\u65b9\\u5f0f\\u53d1\\u653e\\u7ed9\\u60a8\\uff0c\\u4f46\\u662f\\u4efb\\u4f55\\u5f62\\u5f0f\\u7684\\u6743\\u76ca\\u65b9\\u6cd5\\uff0c\\u5708\\u5708\\u90fd\\u4e0d\\u89c6\\u4e3a\\u662f\\u5bf9\\u60a8\\u6240\\u56de\\u6536\\u8863\\u670d\\u7684\\u6709\\u507f\\u62a5\\u916c\\u3002<\\/p><p>&nbsp;\\u4e8c\\u3001\\u4e2a\\u4eba\\u4fe1\\u606f<\\/p><p>&nbsp;1.\\u4f7f\\u7528\\u5708\\u5708\\u670d\\u52a1\\u4f1a\\u9a8c\\u8bc1\\u60a8\\u7684\\u624b\\u673a\\u53f7\\u7801\\uff0c\\u5708\\u5708\\u5728\\u4fdd\\u62a4\\u7528\\u6237\\u9690\\u79c1\\u65b9\\u9762\\u505a\\u4e86\\u5f88\\u591a\\u7684\\u52aa\\u529b\\uff0c\\u5728\\u5708\\u5708\\u7684\\u6240\\u6709\\u7684\\u4ea7\\u54c1\\u4e2d\\uff0c\\u90fd\\u4f7f\\u7528\\u4e86\\u76ee\\u524d\\u6700\\u4e3b\\u6d41\\u7684https\\u52a0\\u5bc6\\u7f51\\u7edc\\u534f\\u8bae\\uff0c\\u5728\\u6570\\u636e\\u53d1\\u9001\\u548c\\u63a5\\u6536\\u7684\\u8fc7\\u7a0b\\u4e2d\\u6700\\u5927\\u9650\\u5ea6\\u7684\\u5e2e\\u52a9\\u7528\\u6237\\u4fdd\\u62a4\\u9690\\u79c1\\u3002<\\/p><p>&nbsp;2.\\u60a8\\u5728\\u4f7f\\u7528\\u5708\\u5708\\u4e0a\\u95e8\\u9884\\u7ea6\\u7684\\u670d\\u52a1\\u4e2d\\uff0c\\u4f1a\\u5411\\u5708\\u5708\\u670d\\u52a1\\u5668\\u53d1\\u9001\\u60a8\\u7684\\u5730\\u5740\\uff0c\\u59d3\\u540d\\u7b49\\u4e2a\\u4eba\\u4fe1\\u606f\\uff0c\\u5708\\u5708\\u59cb\\u7ec8\\u8ba4\\u4e3a\\u7528\\u6237\\u7684\\u4fe1\\u606f\\u662f\\u88ab\\u4e25\\u683c\\u4fdd\\u5bc6\\u7684\\uff0c\\u60a8\\u7684\\u8ba2\\u5355\\u4fe1\\u606f\\u4e0d\\u4f1a\\u63a8\\u9001\\u7ed9\\u4efb\\u4f55 \\u9664\\u4e86\\u76ee\\u524d\\u5fb7\\u90a6\\/\\u987a\\u4e30\\u7b49\\u5177\\u5907\\u5408\\u4f5c\\u8d44\\u683c\\u548c\\u534f\\u8bae\\u7684\\u5feb\\u9012\\u516c\\u53f8\\u4ee5\\u5916\\u7684\\u7b2c\\u4e09\\u65b9\\u673a\\u6784\\u3002<\\/p><p>\\u4e09\\u3001 \\u9875\\u9762\\u6ce8\\u518c&nbsp;<\\/p><p>\\u5f53\\u60a8\\u5728\\u6ce8\\u518c\\u4e3a\\u4f1a\\u5458\\u65f